def rotate_cyclic(self, nums: list[int], k: int) -> None:
    n = len(nums)
    k %= n
    cnt = gcd(k, n)
    for start in range(cnt):
        cur, prev = start, nums[start]
        while True:
            nxt = (cur + k) % n
            nums[nxt], prev = prev, nums[nxt]
            cur = nxt
            if cur == start:
                break
